import { useEffect, useRef, useState } from "react"


const actividades = [
    { reseña: "“Muy lindas cabañas, ubicadas cerca de la ruta en un lugar muy tranquilo! Cómodas y bien equipadas. Excelente la atención, muy amables y responden enseguida, y siempre con una sonrisa. Impecable. Para recomendar sin lugar a dudas! Muchas gracias!!”", usuario:"Ariel RC" },
    { reseña: "“Las cabañas son muy cómodas, con todo lo necesario para pasar una buena estadía. Lugar dentro del predio para estacionar el auto, pileta, quincho compartido y juegos para chicos. Además teníamos una pequeña galería con parrilla y juego de mesa y sillas propio de la cabaña. La atención de Mariana 10 puntos. Volvería a alojarme allí.”", usuario:"Ariel RC" },
    { reseña: "“Muy lindo lugar y recomendable! Tiene parrilla individual, patio de juego para los chicos, patio verde y pileta. la cabaña es amplia equipada con lo más moderno, también tiene cochera es un barrio muy tranquilo sin ruido para descansar de 10 ! Y queda en un punto que estás a 30km de cualquier ciudad como ( Carlos paz, villa belgrano, Córdoba,ect.)”", usuario:"Benjamín R." }
    
]

const OpinionCard=({ titulo, desc, visible, delay }) => (
    <div className="flex-1 bg-white rounded-lg p-3 text-left text-gray-800 shadow-lg transition-all duration-700"
        style={{
            opacity: visible ? 1 : 0,
            transform: visible ? "translateY(0)" : "translateY(40px)",
            transitionDelay: delay,
        }}>
        <h3 className="text-2xl font-playfair mb-2 text-[#F55809] font-bold text-center">{titulo}</h3>
        <p className="font-roboto font-light">{desc}</p>
    </div>
)

const Reseñas = () => {
    const [visible, setVisible] = useState(false)
    const sectionRef = useRef(null)
    useEffect(() => {
        const observer = new IntersectionObserver(
            ([entry]) => { setVisible(entry.isIntersecting) },
            { threshold: 0.3 }
        )
        if (sectionRef.current) {
            observer.observe(sectionRef.current)
        }
        return () => {
            observer.disconnect()
        }
    }, [])  
    return (
        <section className="relative h-screen snap-start flex flex-col items-center justify-center"
            style={{
                background:"linear-gradient(180deg, #F3FEFF 0%, #EFE6D8 49.52%, #D8C4A5 90.38%)",
            }}
            ref={sectionRef}
        >
           
            <div className="relative z-10 flex flex-col items-center gap-8 p-6">
                <h2 className="text-4xl font-playfair text-[#7D6239] text-center transition-all duration-700"
                    style={{
                        opacity: visible ? 1 : 0,
                        transform: visible ? "translateY(0)" : "translateY(20px)",
                        transitionDelay: "0ms",
                    }}
                >
                    Lo que dicen quienes ya nos visitaron
                </h2>
                <div className="flex gap-6 max-w-[65%]">
                    {actividades.map((a, i) => (
                        <OpinionCard key={a.reseña} {...a} visible={visible} delay={`${200 + i * 150}ms`} />
                    ))}
                </div>
            </div>
        </section>
    )
}
export default Reseñas;
